"use client";

import { useMemo } from "react";
import Link from "next/link";
import { MotionReveal } from "./motion-reveal";
import { DeepClinicFxFrame } from "./deepclinic-fx-frame";

type Props = {
  lang?: "es" | "en" | "pt";
};

const CONTENT = {
  es: {
    title: "DeepClinic Comando de Triaje",
    description: "Llega a consulta con el caso listo. Anamnesis automática por voz y texto, clasificación y resumen clínico en minutos.",
    cta: "Ver detalle",
    chat: "Hola, para preparar su consulta, ¿podría decirme qué síntomas ha sentido hoy?",
    voice: "Voz Detectada",
    summary: "Resumen Preliminar",
    priority: "Prioridad Media"
  },
  en: {
    title: "DeepClinic Triage Command",
    description: "Walk into the visit with the case prepared. Automated voice/text intake, triage, and a clean clinical summary in minutes.",
    cta: "View details",
    chat: "Hello, to prepare for your consultation, could you tell me what symptoms you have felt today?",
    voice: "Voice Detected",
    summary: "Preliminary Summary",
    priority: "Medium Priority"
  },
  pt: {
    title: "DeepClinic Comando de Triagem",
    description: "Entre na consulta com o caso pronto. Intake por voz/texto, triagem e resumo clínico claro em minutos.",
    cta: "Ver detalhes",
    chat: "Olá, para preparar sua consulta, poderia me dizer quais sintomas sentiu hoje?",
    voice: "Voz Detectada",
    summary: "Resumo Preliminar",
    priority: "Prioridade Média"
  },
};

export function DeepClinicTriage({ lang = "es" }: Props) {
  const t = CONTENT[lang];
  const accent = "rgba(16,185,129,0.22)";
  const painPoints =
    lang === "es"
      ? ["Caso incompleto", "Triage manual", "Notas dispersas"]
      : lang === "pt"
        ? ["Caso incompleto", "Triagem manual", "Notas dispersas"]
        : ["Incomplete case", "Manual triage", "Scattered notes"];
  const metrics =
    lang === "es"
      ? [
        { label: "Canales", value: "2" },
        { label: "Salida", value: "1" },
        { label: "Tiempo", value: "5 min" },
      ]
      : lang === "pt"
        ? [
          { label: "Canais", value: "2" },
          { label: "Saída", value: "1" },
          { label: "Tempo", value: "5 min" },
        ]
        : [
          { label: "Channels", value: "2" },
          { label: "Output", value: "1" },
          { label: "Time", value: "5 min" },
        ];

  const voiceBars = useMemo(() => {
    return Array.from({ length: 12 }, (_, i) => {
      const x = Math.sin((i + 1) * 999) * 10000;
      const r = x - Math.floor(x);
      return 20 + Math.round(r * 80);
    });
  }, []);

  return (
    <section className="relative z-10 w-full h-[100svh] snap-start snap-always flex items-center px-6 pt-20 pb-12 md:px-8 lg:px-10">
      <div className="mx-auto w-full max-w-screen-2xl">
        <MotionReveal durationMs={740} className="w-full">
          <div className="relative isolate flex min-h-[70svh] items-center overflow-hidden rounded-[32px] border border-white/10 bg-white/[0.02] p-10 md:min-h-[74svh] md:p-14 lg:min-h-[78svh] lg:p-16">
            {/* Background Glows */}
            <div className="pointer-events-none hidden absolute -left-20 -bottom-20 h-[400px] w-[400px] rounded-full bg-white/[0.02] blur-[120px]" />
            <div className="pointer-events-none hidden absolute right-0 top-0 h-[300px] w-[300px] rounded-full bg-white/[0.015] blur-[110px]" />

            <div className="grid w-full gap-10 lg:grid-cols-2 lg:items-center lg:gap-16">

              {/* Content */}
              <div className="relative z-10 max-w-xl">
                <h3 className="text-3xl font-semibold tracking-tight text-white md:text-4xl">
                  {t.title}
                </h3>
                <p className="mt-6 line-clamp-3 text-[13px] leading-relaxed text-white/60 md:text-[14px]">
                  {t.description}
                </p>

                <div className="mt-8 grid gap-4 sm:grid-cols-5">
                  <div className="rounded-2xl border border-white/10 bg-black/30 p-4 sm:col-span-2">
                    <div className="text-[10px] font-semibold uppercase tracking-[0.22em] text-white/35">
                      {lang === "es" ? "Dolor" : lang === "pt" ? "Dor" : "Pain"}
                    </div>
                    <div className="mt-3 flex flex-wrap gap-2">
                      {painPoints.slice(0, 3).map((p) => (
                        <div
                          key={p}
                          className="inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/[0.02] px-3 py-1.5 text-[11px] font-medium text-white/75"
                        >
                          <span
                            className="h-1.5 w-1.5 rounded-full"
                            style={{ background: "rgba(255,255,255,0.24)", boxShadow: `0 0 18px ${accent}` }}
                          />
                          {p}
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="rounded-2xl border border-white/10 bg-black/30 p-4 sm:col-span-3">
                    <div className="text-[10px] font-semibold uppercase tracking-[0.22em] text-white/35">
                      {lang === "es" ? "Impacto" : lang === "pt" ? "Impacto" : "Impact"}
                    </div>
                    <div className="mt-3 grid grid-cols-2 gap-2 sm:grid-cols-3">
                      {metrics.slice(0, 3).map((m, mi) => {
                        const barSets = [
                          [24, 52, 34, 74, 42],
                          [38, 28, 66, 44, 58],
                          [30, 60, 40, 54, 36],
                        ] as const;
                        const bars = barSets[mi % barSets.length];
                        const raw = String(m.value);
                        const space = raw.indexOf(" ");
                        const main = space === -1 ? raw : raw.slice(0, space);
                        const unit = space === -1 ? "" : raw.slice(space + 1);
                        return (
                          <div
                            key={m.label}
                            className="relative min-w-0 overflow-hidden rounded-2xl border border-white/15 bg-white/[0.03] px-3 py-3 sm:px-4"
                          >
                            <div
                              className="pointer-events-none absolute inset-0 opacity-70"
                              style={{
                                background: `radial-gradient(80% 90% at 30% 25%, ${accent}, transparent 62%)`,
                              }}
                            />
                            <div className="flex min-w-0 items-baseline gap-2 whitespace-nowrap">
                              <span
                                className="tabular-nums text-[20px] font-semibold leading-none tracking-tight text-white/90 sm:text-[22px] md:text-[24px] lg:text-[28px]"
                                style={{ textShadow: `0 0 28px ${accent}` }}
                              >
                                {main}
                              </span>
                              {unit ? <span className="text-[10px] font-semibold tracking-tight text-white/70 sm:text-[11px]">{unit}</span> : null}
                            </div>

                            <div className="mt-3 flex h-[22px] items-end gap-1.5">
                              {bars.map((h, bi) => (
                                <div
                                  key={bi}
                                  className="dc_motion w-1.5 origin-bottom rounded-full"
                                  style={{
                                    height: `${h}%`,
                                    background: `linear-gradient(180deg, rgba(255,255,255,0.12), ${accent})`,
                                    boxShadow: `0 0 14px ${accent}`,
                                    animation: "dc_metric_bar 2.8s ease-in-out infinite",
                                    animationDelay: `${-0.25 - (mi * 0.4 + bi * 0.12)}s`,
                                    willChange: "transform, opacity",
                                  }}
                                />
                              ))}
                              <div className="ml-auto h-px w-6 bg-white/10" />
                            </div>

                            <div className="mt-2 truncate text-[8px] font-semibold uppercase tracking-[0.22em] text-white/45 sm:text-[9px]">
                              {m.label}
                            </div>
                            <div
                              className="pointer-events-none absolute inset-x-0 bottom-0 h-px opacity-80"
                              style={{ background: `linear-gradient(90deg, transparent 0%, ${accent} 50%, transparent 100%)` }}
                            />
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="mt-10">
                  <Link
                    href={`/${lang}/booking`}
                    className="inline-flex items-center justify-center rounded-full border border-white/15 bg-white/5 px-8 py-3 text-[10px] font-semibold uppercase tracking-[0.24em] text-white/80"
                  >
                    {t.cta}
                    <span className="ml-2" aria-hidden>
                      ↗
                    </span>
                  </Link>
                </div>
              </div>

              {/* Visual - Triage Simulation */}
              <div className="relative z-10">
                <DeepClinicFxFrame
                  accent={accent}
                  variant="ui"
                  className="relative mx-auto w-full max-w-[640px] xl:max-w-[720px]"
                >
                  <div className="p-7 md:p-8" style={{ transform: "translateZ(18px)" }}>
                    {/* Chat/Voice Interface Simulation */}
                    <div className="space-y-6">

                      {/* Bot Message */}
                      <div className="flex gap-4">
                        <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-emerald-500/20 text-emerald-400">
                          <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                          </svg>
                        </div>
                        <div className="space-y-2">
                          <div className="rounded-2xl rounded-tl-none bg-white/10 p-3 text-xs text-white/80">
                            {t.chat}
                          </div>
                        </div>
                      </div>

                      {/* User Voice Waveform */}
                      <div className="flex flex-col items-end gap-2">
                        <div className="flex items-center gap-1 rounded-2xl rounded-tr-none bg-emerald-500/10 px-4 py-3 border border-emerald-500/20">
                          <span className="text-[10px] uppercase tracking-wider text-emerald-400 mr-2">{t.voice}</span>
                          <div className="flex items-center gap-[2px] h-4">
                            {[...Array(12)].map((_, i) => (
                              <div
                                key={i}
                                className="dc_motion w-[3px] origin-bottom rounded-full bg-emerald-400/60"
                                style={{
                                  height: `${voiceBars[i] ?? 20}%`,
                                  animation: `dc_wave 1.4s ease-in-out infinite ${(i * 0.08).toFixed(2)}s`,
                                }}
                              />
                            ))}
                          </div>
                        </div>
                      </div>

                      {/* Triage Result Card */}
                      <div className="mt-4 rounded-xl border border-white/10 bg-white/[0.03] p-4 backdrop-blur-md">
                        <div className="flex items-center justify-between mb-3">
                          <span className="text-[10px] font-semibold uppercase text-white/40">{t.summary}</span>
                          <span className="rounded bg-yellow-500/20 px-2 py-0.5 text-[9px] font-bold uppercase text-yellow-200">{t.priority}</span>
                        </div>
                        <div className="space-y-2">
                          <div className="h-1.5 w-3/4 rounded-full bg-white/20" />
                          <div className="h-1.5 w-full rounded-full bg-white/10" />
                          <div className="h-1.5 w-5/6 rounded-full bg-white/10" />
                        </div>
                      </div>

                    </div>
                  </div>
                </DeepClinicFxFrame>
              </div>

            </div>
          </div>
        </MotionReveal>
      </div>
    </section>
  );
}
