"use client";

import Link from "next/link";
import { MotionReveal } from "./motion-reveal";
import { DeepClinicFxFrame } from "./deepclinic-fx-frame";

/* Assets */
const WHATSAPP_VIDEO = "/video/day_disconect.mp4";

type Props = {
  lang?: "es" | "en" | "pt";
};

const CONTENT = {
  es: {
    title: "DeepClinic Asistente Clínico en WhatsApp",
    description: "Ahorra hasta 3 horas al día con DeepClinic, sin que nada cambie para tus pacientes.",
    cta: "Ver detalle",
    footer: ""
  },
  en: {
    title: "DeepClinic Clinical Assistant on WhatsApp",
    description: "Save up to 3 hours a day with DeepClinic, without changing anything for your patients.",
    cta: "View details",
    footer: ""
  },
  pt: {
    title: "DeepClinic Assistente Clínico no WhatsApp",
    description: "Economize até 3 horas por dia com DeepClinic, sem mudar nada para seus pacientes.",
    cta: "Ver detalhes",
    footer: ""
  },
};

export function DeepClinicWhatsApp({ lang = "es" }: Props) {
  const t = CONTENT[lang];
  const accent = "rgba(34,197,94,0.22)";
  const painPoints =
    lang === "es"
      ? ["Mensajes sin orden", "Triage manual", "Seguimiento perdido"]
      : lang === "pt"
        ? ["Mensagens sem ordem", "Triagem manual", "Follow-up perdido"]
        : ["Unstructured messages", "Manual triage", "Lost follow-up"];
  const metrics =
    lang === "es"
      ? [
        { label: "Tiempo", value: "3 h/día", note: "ahorro" },
        { label: "Cobertura", value: "24/7", note: "asistencia" },
        { label: "Respuesta", value: "-40%", note: "fricción" },
      ]
      : lang === "pt"
        ? [
          { label: "Tempo", value: "3 h/dia", note: "economia" },
          { label: "Cobertura", value: "24/7", note: "assistência" },
          { label: "Resposta", value: "-40%", note: "atrito" },
        ]
        : [
          { label: "Time", value: "3 h/day", note: "saved" },
          { label: "Coverage", value: "24/7", note: "assist" },
          { label: "Response", value: "-40%", note: "friction" },
        ];
  return (
    <section className="relative z-10 w-full h-[100svh] snap-start snap-always flex items-center px-6 pt-20 pb-12 md:px-8 lg:px-10">
      <div className="mx-auto w-full max-w-screen-2xl">
        <MotionReveal durationMs={740} className="w-full">
          <div className="relative isolate flex min-h-[70svh] items-center overflow-hidden rounded-[32px] border border-white/10 bg-white/[0.02] p-10 md:min-h-[74svh] md:p-14 lg:min-h-[78svh] lg:p-16 text-white">

            {/* Background Glows */}
            <div className="pointer-events-none hidden absolute -left-20 -bottom-20 h-[400px] w-[400px] rounded-full bg-white/[0.02] blur-[120px]" />
            <div className="pointer-events-none hidden absolute right-0 top-0 h-[300px] w-[300px] rounded-full bg-white/[0.015] blur-[110px]" />

            <div className="grid w-full gap-10 lg:grid-cols-2 lg:items-center lg:gap-16">
              {/* Content */}
              <div className="relative z-10 max-w-xl">
                <h3 className="text-3xl font-semibold tracking-tight text-white md:text-4xl">
                  {t.title}
                </h3>
                <p className="mt-6 line-clamp-3 text-[13px] leading-relaxed text-white/60 md:text-[14px]">
                  {t.description}
                </p>

                <div className="mt-8 grid gap-4 sm:grid-cols-5">
                  <div className="rounded-2xl border border-white/10 bg-black/30 p-4 sm:col-span-2">
                    <div className="text-[10px] font-semibold uppercase tracking-[0.22em] text-white/35">
                      {lang === "es" ? "Dolor" : lang === "pt" ? "Dor" : "Pain"}
                    </div>
                    <div className="mt-3 flex flex-wrap gap-2">
                      {painPoints.slice(0, 3).map((p) => (
                        <div
                          key={p}
                          className="inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/[0.02] px-3 py-1.5 text-[11px] font-medium text-white/75"
                        >
                          <span className="h-1.5 w-1.5 rounded-full" style={{ background: "rgba(255,255,255,0.24)", boxShadow: `0 0 18px ${accent}` }} />
                          {p}
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="rounded-2xl border border-white/10 bg-black/30 p-4 sm:col-span-3">
                    <div className="text-[10px] font-semibold uppercase tracking-[0.22em] text-white/35">
                      {lang === "es" ? "Impacto" : lang === "pt" ? "Impacto" : "Impact"}
                    </div>
                    <div className="mt-3 grid grid-cols-2 gap-2 sm:grid-cols-3">
                      {metrics.slice(0, 3).map((m, mi) => {
                        const barSets = [
                          [24, 52, 34, 74, 42],
                          [38, 28, 66, 44, 58],
                          [30, 60, 40, 54, 36],
                        ] as const;
                        const bars = barSets[mi % barSets.length];
                        const raw = String(m.value);
                        const space = raw.indexOf(" ");
                        const main = space === -1 ? raw : raw.slice(0, space);
                        const unit = space === -1 ? "" : raw.slice(space + 1);
                        return (
                          <div
                            key={m.label}
                            className="relative min-w-0 overflow-hidden rounded-2xl border border-white/15 bg-white/[0.03] px-3 py-3 sm:px-4"
                          >
                            <div
                              className="pointer-events-none absolute inset-0 opacity-70"
                              style={{
                                background: `radial-gradient(80% 90% at 30% 25%, ${accent}, transparent 62%)`,
                              }}
                            />
                            <div className="flex min-w-0 items-baseline gap-2 whitespace-nowrap">
                              <span
                                className="tabular-nums text-[20px] font-semibold leading-none tracking-tight text-white/90 sm:text-[22px] md:text-[24px] lg:text-[28px]"
                                style={{ textShadow: `0 0 28px ${accent}` }}
                              >
                                {main}
                              </span>
                              {unit ? <span className="text-[10px] font-semibold tracking-tight text-white/70 sm:text-[11px]">{unit}</span> : null}
                            </div>

                            <div className="mt-3 flex h-[22px] items-end gap-1.5">
                              {bars.map((h, bi) => (
                                <div
                                  key={bi}
                                  className="dc_motion w-1.5 origin-bottom rounded-full"
                                  style={{
                                    height: `${h}%`,
                                    background: `linear-gradient(180deg, rgba(255,255,255,0.12), ${accent})`,
                                    boxShadow: `0 0 14px ${accent}`,
                                    animation: "dc_metric_bar 2.8s ease-in-out infinite",
                                    animationDelay: `${-0.25 - (mi * 0.4 + bi * 0.12)}s`,
                                    willChange: "transform, opacity",
                                  }}
                                />
                              ))}
                              <div className="ml-auto h-px w-6 bg-white/10" />
                            </div>

                            <div className="mt-2 truncate text-[8px] font-semibold uppercase tracking-[0.22em] text-white/45 sm:text-[9px]">
                              {m.label}
                            </div>
                            <div
                              className="pointer-events-none absolute inset-x-0 bottom-0 h-px opacity-80"
                              style={{ background: `linear-gradient(90deg, transparent 0%, ${accent} 50%, transparent 100%)` }}
                            />
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>

                <div className="mt-10">
                  <Link
                    href={`/${lang}/product`}
                    className="inline-flex items-center justify-center rounded-full border border-white/15 bg-white/5 px-8 py-3 text-[10px] font-semibold uppercase tracking-[0.24em] text-white/80"
                  >
                    {t.cta}
                    <span className="ml-2" aria-hidden>
                      ↗
                    </span>
                  </Link>
                </div>
              </div>

              {/* Image */}
              <div className="relative z-10">
                <DeepClinicFxFrame accent={accent} variant="video">
                  <video
                    className="h-auto w-full object-cover aspect-[4/3]"
                    src={WHATSAPP_VIDEO}
                    autoPlay
                    loop
                    muted
                    playsInline
                    preload="metadata"
                    aria-label={
                      lang === "es"
                        ? "Demo de DeepClinic en WhatsApp"
                        : lang === "pt"
                          ? "Demonstração da DeepClinic no WhatsApp"
                          : "DeepClinic WhatsApp demo"
                    }
                  />
                </DeepClinicFxFrame>
              </div>
            </div>

            {/* Social Proof / Logos */}
            {t.footer ? (
              <div className="mt-20 flex flex-col items-center gap-8 text-center">
                <p className="text-sm font-medium text-white/50">{t.footer}</p>
              </div>
            ) : null}

          </div>
        </MotionReveal>
      </div>
    </section>
  );
}
